// Diff-Tool. Zeilenweiser Multiset-Vergleich zweier Texte a und b.
async function run(input) {
  var a = String((input && input.a) || '');
  var b = String((input && input.b) || '');
  var linesA = a.split('\n');
  var linesB = b.split('\n');
  function countMap(arr) {
    var m = {};
    arr.forEach(function (l) { m[l] = (m[l] || 0) + 1; });
    return m;
  }
  var mapA = countMap(linesA);
  var mapB = countMap(linesB);
  var hinzugefuegt = [];
  var entfernt = [];
  var unveraendert = 0;
  Object.keys(mapB).forEach(function (l) {
    var inA = mapA[l] || 0;
    var inB = mapB[l];
    var common = Math.min(inA, inB);
    unveraendert += common;
    for (var i = 0; i < inB - common; i++) hinzugefuegt.push(l);
  });
  Object.keys(mapA).forEach(function (l) {
    var inA = mapA[l];
    var inB = mapB[l] || 0;
    for (var i = 0; i < inA - Math.min(inA, inB); i++) entfernt.push(l);
  });
  return { identisch: a === b, hinzugefuegt: hinzugefuegt, entfernt: entfernt, unveraendert: unveraendert };
}
